import { useNavigate } from "react-router-dom";

function MainBtns({Text,NavigateTo, FontSize, Style, Width, Height, FontWeight, Padding, Margin,MarginTop}) {
  
  const navigate = useNavigate();
  console.log("zxc")
  return (
    <div className={"main-btn "+Style} style={{fontSize:FontSize,
    width:Width,
    height:Height,
    fontWeight:FontWeight,
    padding:Padding,
    margin:Margin,
    marginTop:MarginTop}}

    onClick={()=>navigate(NavigateTo)}
    >
      {Text}
    </div>
  );
}

export default MainBtns;
